const d = $input.first().json;
const f = v => (v && String(v).trim()) ? String(v).trim() : '\u2014';
const esc = s => String(s || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;');

const urgColors = {
  'Do 24 hodin': '#dc2626',
  'Tento týden':  '#ea580c',
  'Tento měsíc':  '#ca8a04',
  'Flexibilní':   '#16a34a'
};
const urgColor = urgColors[d.urgence] || '#6366f1';

const nabidkaItems = [d.nabidka_1, d.nabidka_2, d.nabidka_3]
  .filter(x => x && x.trim())
  .map((x, i) => `<li>${i + 1}. ${esc(x)}</li>`)
  .join('') || '<li>\u2014</li>';

const ts = new Date(d.odeslano || Date.now())
  .toLocaleString('cs-CZ', { dateStyle: 'long', timeStyle: 'short' });

/* ── EMAIL JANOVI ─────────────────────────────────────────────── */
const janHtml = `<!DOCTYPE html>
<html lang="cs"><head><meta charset="UTF-8">
<style>
*{box-sizing:border-box}
body{margin:0;padding:20px;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}
.wrap{max-width:680px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,.10)}
.hdr{background:linear-gradient(135deg,#1e1b4b,#312e81);padding:36px;color:#fff}
.badge{display:inline-block;background:${urgColor};color:#fff;padding:5px 14px;border-radius:100px;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.5px}
.hdr h1{margin:12px 0 4px;font-size:22px}
.ts{color:rgba(255,255,255,.6);font-size:13px}
.body{padding:36px}
.crow{display:flex;flex-wrap:wrap;gap:16px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:10px;padding:18px 20px;margin-bottom:28px}
.ci{flex:1;min-width:140px}
.ci .lbl{font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px}
.ci .val{font-size:14px;color:#1e3a8a;font-weight:700}
.ci a{color:#1e3a8a}
.sec{margin-bottom:24px}
.st{font-size:10px;text-transform:uppercase;letter-spacing:1px;color:#94a3b8;font-weight:700;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid #f1f5f9}
.row{display:flex;gap:8px;margin-bottom:7px}
.rl{font-size:12px;color:#94a3b8;min-width:160px;flex-shrink:0}
.rv{font-size:13px;color:#1e293b;font-weight:500;line-height:1.5}
.prompt-box{background:#0f172a;border-radius:10px;padding:24px;margin-top:8px}
.prompt-box pre{color:#e2e8f0;font-family:'Courier New',monospace;font-size:11px;line-height:1.7;margin:0;white-space:pre-wrap;word-break:break-word}
.div{height:1px;background:#f1f5f9;margin:24px 0}
.ftr{background:#f8fafc;padding:14px 36px;font-size:12px;color:#94a3b8;border-top:1px solid #e2e8f0}
a{color:#6366f1}
ul{margin:4px 0;padding-left:20px}
ul li{margin-bottom:3px;font-size:13px;color:#1e293b}
</style></head>
<body><div class="wrap">
<div class="hdr">
  <span class="badge">${esc(f(d.urgence))}</span>
  <h1>🔥 Nová poptávka — ${esc(f(d.firma))}</h1>
  <div class="ts">${ts}</div>
</div>
<div class="body">
  <div class="crow">
    <div class="ci"><div class="lbl">Jméno</div><div class="val">${esc(f(d.kontakt_jmeno))}</div></div>
    <div class="ci"><div class="lbl">E-mail</div><div class="val"><a href="mailto:${esc(f(d.kontakt_email))}">${esc(f(d.kontakt_email))}</a></div></div>
    <div class="ci"><div class="lbl">Telefon</div><div class="val">${d.kontakt_telefon ? `<a href="tel:${esc(d.kontakt_telefon)}">${esc(d.kontakt_telefon)}</a>` : '\u2014'}</div></div>
  </div>
  <div class="sec">
    <div class="st">Firma & projekt</div>
    <div class="row"><div class="rl">Název</div><div class="rv">${esc(f(d.firma))}</div></div>
    <div class="row"><div class="rl">Popis</div><div class="rv">${esc(f(d.cinnost))}</div></div>
    <div class="row"><div class="rl">Působnost</div><div class="rv">${esc(f(d.pusobnost))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Unikátní hodnota</div>
    <div class="row"><div class="rl">Proč si je vybírají</div><div class="rv">${esc(f(d.uvp))}</div></div>
    <div class="row"><div class="rl">Jsme jediní, kdo…</div><div class="rv">${esc(f(d.jedini_kdo))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Zákazník</div>
    <div class="row"><div class="rl">Popis</div><div class="rv">${esc(f(d.zakaznik_popis))}</div></div>
    <div class="row"><div class="rl">Problém před</div><div class="rv">${esc(f(d.problem_pred))}</div></div>
    <div class="row"><div class="rl">Výsledek po</div><div class="rv">${esc(f(d.vysledek_po))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Nabídka</div>
    <ul>${nabidkaItems}</ul>
    <div class="row" style="margin-top:10px"><div class="rl">Hero offer</div><div class="rv">${esc(f(d.hero_offer))}</div></div>
    <div class="row"><div class="rl">Cenové rozpětí</div><div class="rv">${esc(f(d.cena))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Důvěra & social proof</div>
    <div class="row"><div class="rl">Čísla & fakta</div><div class="rv">${esc(f(d.duvera_cisla))}</div></div>
    <div class="row"><div class="rl">Nejsilnější reference</div><div class="rv">${esc(f(d.duvera_reference))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Konverze</div>
    <div class="row"><div class="rl">Hlavní CTA</div><div class="rv">${esc(f(d.cil))}</div></div>
    <div class="row"><div class="rl">Kontakt na webu</div><div class="rv">${esc(f(d.kontakt_udaje))}</div></div>
    <div class="row"><div class="rl">Vstupní nabídka</div><div class="rv">${esc(f(d.vstupni_nabidka))}</div></div>
  </div>
  <div class="sec">
    <div class="st">Brand & design</div>
    <div class="row"><div class="rl">Tón komunikace</div><div class="rv">${esc(f(d.ton))}</div></div>
    <div class="row"><div class="rl">Brand slova</div><div class="rv">${esc(f(d.brand_slova))}</div></div>
    <div class="row"><div class="rl">Vyhnout se</div><div class="rv">${esc(f(d.vyhnout_se))}</div></div>
    <div class="row"><div class="rl">Vizuální styl</div><div class="rv">${esc(f(d.styl))}</div></div>
    <div class="row"><div class="rl">Vzorový web</div><div class="rv">${d.vzor_web ? `<a href="${esc(d.vzor_web)}">${esc(d.vzor_web)}</a>` : '\u2014'}</div></div>
    <div class="row"><div class="rl">Materiály</div><div class="rv">${esc(f(d.logo_fotky))}</div></div>
  </div>
  ${d.must_have ? `<div class="sec"><div class="st">Musí tam být</div><div class="rv" style="white-space:pre-wrap">${esc(d.must_have)}</div></div>` : ''}
  <div class="div"></div>
  <div class="sec">
    <div class="st">📋 Vygenerovaný AI prompt</div>
    <div class="prompt-box">
      <pre>${esc(d.generatedPrompt || '\u2014 prompt nebyl vygenerován \u2014')}</pre>
    </div>
  </div>
</div>
<div class="ftr">webdo24.cz &nbsp;&bull;&nbsp; ${ts} &nbsp;&bull;&nbsp; <a href="${esc(d.zdroj || 'https://webdo24.cz')}">webdo24.cz</a></div>
</div></body></html>`;

/* ── AUTO-REPLY ZÁKAZNÍKOVI ──────────────────────────────────── */
const customerHtml = `<!DOCTYPE html>
<html lang="cs"><head><meta charset="UTF-8">
<style>
*{box-sizing:border-box}
body{margin:0;padding:20px;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}
.wrap{max-width:560px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,.10)}
.hdr{background:linear-gradient(135deg,#1e1b4b,#312e81);padding:48px 36px;text-align:center;color:#fff}
.hdr .ico{font-size:52px;margin-bottom:16px}
.hdr h1{margin:0;font-size:24px}
.body{padding:40px 36px}
.body p{color:#475569;line-height:1.75;margin:0 0 16px}
.hl{background:#eff6ff;border-left:4px solid #6366f1;padding:16px 20px;border-radius:0 8px 8px 0;margin:24px 0;color:#1e3a8a;font-weight:600}
ul{color:#475569;line-height:1.9;padding-left:20px;margin:0 0 16px}
.cb{background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:20px 24px;margin-top:28px}
.cb p{margin:0 0 8px;color:#64748b;font-size:13px}
.cb a{color:#6366f1;font-weight:700;font-size:15px;display:block;margin-bottom:6px}
.ftr{background:#f8fafc;padding:14px 36px;font-size:12px;color:#94a3b8;text-align:center;border-top:1px solid #e2e8f0}
</style></head>
<body><div class="wrap">
<div class="hdr">
  <div class="ico">🎉</div>
  <h1>Poptávka přijata!</h1>
</div>
<div class="body">
  <p>Ahoj <strong>${esc(f(d.kontakt_jmeno))}</strong>,</p>
  <p>přijal jsem vaši poptávku pro <strong>${esc(f(d.firma))}</strong>. Ozvu se vám osobně do hodiny (Po–Pá 8:00–20:00).</p>
  <div class="hl">⚡ Váš požadovaný termín: <strong>${esc(f(d.urgence))}</strong></div>
  <p><strong>Mezitím si připravte:</strong></p>
  <ul>
    <li>Logo (pokud máte)</li>
    <li>Fotky z vašeho prostředí nebo produktů</li>
    <li>Texty, které chcete použít <em>(nepovinné — napíšu za vás)</em></li>
  </ul>
  <div class="cb">
    <p>Potřebujete něco upřesnit? Ozvěte se:</p>
    <a href="tel:+420777123456">+420 777 123 456</a>
    <a href="mailto:jan@webdo24.cz">jan@webdo24.cz</a>
  </div>
</div>
<div class="ftr">webdo24.cz &nbsp;&bull;&nbsp; Profesionální weby do 24 hodin</div>
</div></body></html>`;

return [{
  json: {
    ...d,
    emailJan: janHtml,
    emailCustomer: customerHtml,
    subjectJan: '🔥 Nová poptávka: ' + f(d.firma) + ' — ' + f(d.urgence),
    subjectCustomer: 'Přijal jsem vaši poptávku — ozvu se do hodiny \u2713',
    hasEmail: !!(d.kontakt_email && d.kontakt_email.includes('@'))
  }
}];
